

export default function SiteTopBar() {
  const rotatingMessageClass =
    "absolute inset-0 flex items-center justify-center whitespace-nowrap [animation:top-bar-message_8s_linear_infinite_both] [will-change:transform,opacity]";

  return (
    <div className="flex h-7 items-center justify-between gap-3 bg-[#c4d9d8] px-4 text-xs uppercase tracking-[0.12em] text-gray-800">
      <span className="shrink-0">Your fixed text</span>

      <span className="relative block h-[1.2em] min-w-0 grow overflow-hidden text-center leading-none">
        <span className={rotatingMessageClass}>
          FREE SHIPPING for all orders over $50
        </span>
        <span className={`${rotatingMessageClass} [animation-delay:4s]`}>
          Envelopes included
        </span>
      </span>

      <span className="shrink-0"></span>
    </div>
  );
}